import{E as e,F as t,N as n,T as r,a as i,b as a,g as o,j as s,m as c,r as l,w as u,y as d}from"./index-ChqmyjCp.js";var f={class:`content-main`},p={class:`content-wrapper`},m={class:`sidebar-container`},h={class:`sticky-toc`},g={class:`toc-list`},_=[`onClick`],v=l({__name:`PrivacyPolicyView`,setup(l){let v=i(),y=s(JSON.parse(localStorage.getItem(`user`)||`{}`)),b=s(`intro`),x=[{id:`intro`,label:`1. Introduction`},{id:`information-collect`,label:`2. Information We Collect`},{id:`purpose`,label:`3. Purpose of Collection`},{id:`data-sharing`,label:`4. Data Sharing and Disclosure`},{id:`data-security`,label:`5. Data Security`},{id:`data-retention`,label:`6. Data Retention`},{id:`your-rights`,label:`7. Your Rights`},{id:`contact`,label:`8. Contact Information`},{id:`updates`,label:`9. Updates to this Statement`}],S=e=>{b.value=e;let t=document.getElementById(e);if(t){let e=t.getBoundingClientRect().top+window.scrollY+-96;window.scrollTo({top:e,behavior:`smooth`})}};return u(()=>{(!y.value.id||y.value.role!==`college`)&&v.push(`/login`)}),(i,s)=>(r(),d(c,null,[o(`main`,f,[o(`div`,p,[o(`div`,m,[o(`div`,h,[s[0]||=o(`h3`,{class:`toc-title`},` Table of Contents `,-1),o(`ul`,g,[(r(),d(c,null,e(x,e=>o(`li`,{key:e.id},[o(`button`,{onClick:t=>S(e.id),class:n([`sidebar-nav-item`,{"active-nav-item":b.value===e.id}])},t(e.label),11,_)])),64))])])]),s[1]||=a(`<div class="content-area" data-v-7be963b4><div class="policy-card" data-v-7be963b4><div id="introduction" class="policy-section" data-v-7be963b4><div class="policy-header" data-v-7be963b4><div data-v-7be963b4><h1 class="policy-title" data-v-7be963b4>Data Privacy Statement</h1><p class="policy-subtitle" data-v-7be963b4> Benguet State University - Gender and Development Activities Management System (GAD-AMS) </p></div></div></div><div id="intro" class="policy-section" data-v-7be963b4><h2 class="section-heading" data-v-7be963b4>1. Introduction</h2><p class="section-text" data-v-7be963b4> Benguet State University (BSU) is committed to protecting the privacy and confidentiality of personal information collected, stored, and processed through the Gender and Development Activities Management System (GAD-AMS). This Data Privacy Statement outlines our practices regarding the collection, use, and protection of your personal data in compliance with the Data Privacy Act of 2012 (Republic Act No. 10173). </p></div><div id="information-collect" class="policy-section" data-v-7be963b4><h2 class="section-heading" data-v-7be963b4>2. Information We Collect</h2><p class="section-text" data-v-7be963b4> The GAD-AMS collects the following types of personal information: </p><ul class="styled-list" data-v-7be963b4><li data-v-7be963b4>Full name and contact information (<span class="highlight-text" data-v-7be963b4>email address, office/department</span>)</li><li data-v-7be963b4>Activity design and accomplishment report submissions</li><li data-v-7be963b4>Budget utilization data and financial information</li><li data-v-7be963b4>Attendance records and participant demographics (<span class="highlight-text" data-v-7be963b4>sex-disaggregated data</span>)</li><li data-v-7be963b4>User activity logs and system access records</li></ul></div><div id="purpose" class="policy-section" data-v-7be963b4><h2 class="section-heading" data-v-7be963b4>3. Purpose of Collection</h2><p class="section-text" data-v-7be963b4> Your personal information is collected and processed for the following purposes: </p><ul class="styled-list" data-v-7be963b4><li data-v-7be963b4>Processing and evaluation of GAD activity designs and accomplishment reports</li><li data-v-7be963b4>Generation of GAD Plan and Budget (GPB) reports</li><li data-v-7be963b4>Monitoring and evaluation of GAD program implementation</li><li data-v-7be963b4>Compliance with government reporting requirements (<span class="highlight-text" data-v-7be963b4>PCW, CHED, DBM</span>)</li><li data-v-7be963b4>Research and statistical analysis for GAD program improvement</li></ul></div><div id="data-sharing" class="policy-section" data-v-7be963b4><h2 class="section-heading" data-v-7be963b4>4. Data Sharing and Disclosure</h2><p class="section-text" data-v-7be963b4> BSU may share aggregated, anonymized data with government agencies such as the Philippine Commission on Women (PCW), Commission on Higher Education (CHED), and Department of Budget and Management (DBM) for reporting purposes. Personal information is not shared with third parties without your explicit consent, unless required by law. </p></div><div id="data-security" class="policy-section" data-v-7be963b4><h2 class="section-heading" data-v-7be963b4>5. Data Security</h2><p class="section-text" data-v-7be963b4> BSU implements appropriate organizational, physical, and technical security measures to protect personal information from unauthorized access, alteration, disclosure, or destruction. These measures include access controls, encryption, regular security audits, and staff training on data protection. </p></div><div id="data-retention" class="policy-section" data-v-7be963b4><h2 class="section-heading" data-v-7be963b4>6. Data Retention</h2><p class="section-text" data-v-7be963b4> Personal information is retained only for as long as necessary to fulfill the purposes for which it was collected, or as required by applicable laws and regulations. GAD records are typically retained for a period of ten (10) years in accordance with government archival requirements. </p></div><div id="your-rights" class="policy-section" data-v-7be963b4><h2 class="section-heading" data-v-7be963b4>7. Your Rights</h2><p class="section-text" data-v-7be963b4> Under the Data Privacy Act, you have the right to: </p><ul class="styled-list" data-v-7be963b4><li data-v-7be963b4>Access your personal information</li><li data-v-7be963b4>Rectify inaccurate or incomplete data</li><li data-v-7be963b4>Request deletion or blocking of your data</li><li data-v-7be963b4>Object to the processing of your data</li><li data-v-7be963b4>Data portability</li></ul></div><div id="contact" class="policy-section" data-v-7be963b4><h2 class="section-heading" data-v-7be963b4>8. Contact Information</h2><p class="section-text" data-v-7be963b4>For questions, concerns, or requests regarding your personal data, please contact:</p><div class="contact-box" data-v-7be963b4><p class="contact-title" data-v-7be963b4>Data Protection Officer</p><p class="contact-text" data-v-7be963b4>Benguet State University</p><p class="contact-text" data-v-7be963b4>La Trinidad, Benguet 2601</p><p class="contact-email" data-v-7be963b4>Email: dpo@bsu.edu.ph</p><p class="contact-text" data-v-7be963b4>Tel: (074) 422-2401</p></div></div><div id="updates" class="policy-section" data-v-7be963b4><h2 class="section-heading" data-v-7be963b4>9. Updates to this Statement</h2><p class="section-text" data-v-7be963b4> This Data Privacy Statement may be updated periodically. Users will be notified of significant changes through the system or via email. The effective date of the current version is displayed below. </p><p class="effective-date" data-v-7be963b4>Effective Date: January 1, 2026</p></div></div></div>`,1)])]),s[2]||=o(`footer`,{class:`footer-watermark`},[o(`p`,{class:`watermark-text`},` Benguet State University - Gender and Development Activities Management System | GAD-AMS v1.0 `)],-1)],64))}},[[`__scopeId`,`data-v-7be963b4`]]);export{v as default};